function pr_cols(PDO $pdo): array { static $c=null; if(is_array($c))return $c; $c=[]; $s=$pdo->query("SELECT column_name FROM information_schema.columns WHERE table_schema='public' AND table_name='activities'"); foreach($s->fetchAll(PDO::FETCH_ASSOC) as $r){ if(isset($r['column_name']))$c[]=(string)$r['column_name']; } return $c; }
function pr_default_title(): string { return 'Pronunciation'; }
function pr_title(string $v): string { $v=trim($v); return $v!==''?$v:pr_default_title(); }
function pr_resolve_unit(PDO $pdo,string $id): string { if($id==='')return ''; $cols=pr_cols($pdo); foreach(['unit_id','unit'] as $col){ if(!in_array($col,$cols,true))continue; $st=$pdo->prepare("SELECT {$col} FROM activities WHERE id=:id LIMIT 1"); $st->execute(['id'=>$id]); $v=$st->fetchColumn(); if($v!==false && trim((string)$v)!=='')return (string)$v; } return ''; }
function pr_normalize($raw): array { $d=is_string($raw)&&trim($raw)!==''?json_decode($raw,true):(is_array($raw)?$raw:[]); if(!is_array($d))$d=[]; $src=$d['items']??($d['data']??($d['words']??[])); if(!is_array($src))$src=[]; $items=[]; foreach($src as $it){ if(!is_array($it))continue; $en=trim((string)($it['en']??$it['word']??'')); $items[]=['img'=>trim((string)($it['img']??$it['image']??'')),'en'=>$en,'word'=>$en,'ph'=>trim((string)($it['ph']??'')),'es'=>trim((string)($it['es']??'')),'voice_id'=>trim((string)($it['voice_id']??'nzFihrBIvB34imQBuxub')),'audio'=>trim((string)($it['audio']??'')),'example'=>trim((string)($it['example']??'')),'ipa'=>trim((string)($it['ipa']??'')),'meaning'=>trim((string)($it['meaning']??''))]; } return ['title'=>pr_title((string)($d['title']??'')),'items'=>$items]; }
function pr_encode(string $title,array $items): string { return json_encode(['title'=>pr_title($title),'items'=>array_values($items)],JSON_UNESCAPED_UNICODE); }
function pr_load(PDO $pdo,string $unit,string $id): array { $cols=pr_cols($pdo); $fields=['id']; foreach(['data','content_json','title','name'] as $f)if(in_array($f,$cols,true))$fields[]=$f; $row=null; if($id!==''){ $st=$pdo->prepare('SELECT '.implode(',',$fields)." FROM activities WHERE id=:id AND type='pronunciation' LIMIT 1"); $st->execute(['id'=>$id]); $row=$st->fetch(PDO::FETCH_ASSOC); } foreach(['unit_id','unit'] as $col){ if($row||$unit===''||!in_array($col,$cols,true))continue; $st=$pdo->prepare('SELECT '.implode(',',$fields)." FROM activities WHERE {$col}=:unit AND type='pronunciation' ORDER BY id ASC LIMIT 1"); $st->execute(['unit'=>$unit]); $row=$st->fetch(PDO::FETCH_ASSOC); } if(!$row)return ['id'=>'','title'=>pr_default_title(),'items'=>[]]; $p=pr_normalize($row['data']??($row['content_json']??'')); $dbt=trim((string)($row['title']??$row['name']??'')); if($dbt!=='')$p['title']=$dbt; $p['id']=(string)($row['id']??''); return $p; }
function pr_save(PDO $pdo,string $unit,string $id,string $title,array $items): string { $cols=pr_cols($pdo); $json=pr_encode($title,$items); $target=$id; if($target===''){ foreach(['unit_id','unit'] as $col){ if($target!==''||!in_array($col,$cols,true))continue; $st=$pdo->prepare("SELECT id FROM activities WHERE {$col}=:unit AND type='pronunciation' ORDER BY id ASC LIMIT 1"); $st->execute(['unit'=>$unit]); $target=trim((string)$st->fetchColumn()); }} if($target!==''){ $sets=[]; $params=['id'=>$target,'data'=>$json,'title'=>pr_title($title)]; if(in_array('data',$cols,true))$sets[]='data=:data'; if(in_array('content_json',$cols,true))$sets[]='content_json=:data'; if(in_array('title',$cols,true))$sets[]='title=:title'; if(in_array('name',$cols,true))$sets[]='name=:title'; $st=$pdo->prepare('UPDATE activities SET '.implode(',',$sets)." WHERE id=:id AND type='pronunciation'"); $st->execute($params); return $target; } $new=md5(random_bytes(16)); $ic=[];$iv=[];$p=[]; if(in_array('id',$cols,true)){ $ic[]='id';$iv[]=':id';$p['id']=$new; } if(in_array('unit_id',$cols,true)){ $ic[]='unit_id';$iv[]=':unit';$p['unit']=$unit; } elseif(in_array('unit',$cols,true)){ $ic[]='unit';$iv[]=':unit';$p['unit']=$unit; } $ic[]='type';$iv[]="'pronunciation'"; if(in_array('data',$cols,true)){ $ic[]='data';$iv[]=':data';$p['data']=$json; } if(in_array('content_json',$cols,true)){ $ic[]='content_json';$iv[]=':data';$p['data']=$json; } if(in_array('title',$cols,true)){ $ic[]='title';$iv[]=':title';$p['title']=pr_title($title); } if(in_array('name',$cols,true)){ $ic[]='name';$iv[]=':title';$p['title']=pr_title($title); } $st=$pdo->prepare('INSERT INTO activities ('.implode(',',$ic).') VALUES ('.implode(',',$iv).')'); $st->execute($p); return $new; }

if($unit===''&&$activityId!=='')$unit=pr_resolve_unit($pdo,$activityId); if($unit==='')die('Unit not specified');
$activity=pr_load($pdo,$unit,$activityId); $items=is_array($activity['items']??null)?$activity['items']:[]; $activityTitle=(string)($activity['title']??pr_default_title()); if($activityId===''&&!empty($activity['id']))$activityId=(string)$activity['id'];

if($_SERVER['REQUEST_METHOD']==='POST'){
    $title=trim((string)($_POST['activity_title']??'')); $ens=is_array($_POST['en']??null)?$_POST['en']:[]; $phs=is_array($_POST['ph']??null)?$_POST['ph']:[]; $ess=is_array($_POST['es']??null)?$_POST['es']:[]; $imgs=is_array($_POST['img']??null)?$_POST['img']:[]; $audios=is_array($_POST['audio']??null)?$_POST['audio']:[]; $voices=is_array($_POST['voice_id']??null)?$_POST['voice_id']:[]; $examples=is_array($_POST['example']??null)?$_POST['example']:[]; $ipas=is_array($_POST['ipa']??null)?$_POST['ipa']:[]; $meanings=is_array($_POST['meaning']??null)?$_POST['meaning']:[]; $files=$_FILES['img_file']??null; $out=[];
    foreach($ens as $i=>$raw){ $en=trim((string)$raw); $img=trim((string)($imgs[$i]??'')); if($files&&!empty($files['tmp_name'][$i])){ $up=upload_to_cloudinary($files['tmp_name'][$i]); if($up)$img=$up; } $ph=trim((string)($phs[$i]??'')); $es=trim((string)($ess[$i]??'')); $example=trim((string)($examples[$i]??'')); $ipa=trim((string)($ipas[$i]??'')); $meaning=trim((string)($meanings[$i]??'')); if($en===''&&$img===''&&$ph===''&&$es===''&&$ipa===''&&$meaning===''&&$example==='')continue; $out[]=['img'=>$img,'en'=>$en,'word'=>$en,'ph'=>$ph,'es'=>$es,'example'=>$example,'ipa'=>$ipa,'meaning'=>$meaning,'voice_id'=>trim((string)($voices[$i]??'nzFihrBIvB34imQBuxub'))?:'nzFihrBIvB34imQBuxub','audio'=>trim((string)($audios[$i]??''))]; }
    $saved=pr_save($pdo,$unit,$activityId,$title,$out); $params=['unit='.urlencode($unit),'saved=1','id='.urlencode($saved)]; if($assignment!=='')$params[]='assignment='.urlencode($assignment); if($source!=='')$params[]='source='.urlencode($source); header('Location: editor.php?'.implode('&',$params)); exit;
}

ob_start();
