<script>
let formChanged=false,formSubmitted=false;function markAsChanged(){formChanged=true}function removeItem(btn){const b=btn.closest('.pron-block');if(b){b.remove();markAsChanged()}}function addItem(){document.getElementById('items').insertAdjacentHTML('beforeend','<div class="pron-block word-row"><label>Command / Word (English)</label><input class="word-input" type="text" name="en[]" placeholder="coral reef" required><div class="small-grid"><div><label>Phonetic help</label><input type="text" name="ph[]" placeholder="kor-al reef"></div><div><label>Spanish</label><input type="text" name="es[]" placeholder="arrecife de coral"></div></div><label>Example sentence (optional)</label><input class="example-input" type="text" name="example[]" placeholder="The coral reef was full of colorful fish."><div class="ipa-meaning-row"><input class="ipa-input" type="text" name="ipa[]" placeholder="/ˈkɒr.əl riːf/"><input class="meaning-input" type="text" name="meaning[]" placeholder="Short meaning in English"><button type="button" class="autofill-btn">Auto-fill pronunciation &amp; meaning</button></div><div class="status"></div><label>Image (optional)</label><input type="file" name="img_file[]" accept="image/*"><input type="hidden" name="img[]" value=""><input type="hidden" name="audio[]" value=""><input type="hidden" name="voice_id[]" value="nzFihrBIvB34imQBuxub"><button type="button" onclick="removeItem(this)" class="btn-remove">✖ Remove</button></div>');bindChangeTracking(document.getElementById('items').lastElementChild);markAsChanged()}function bindChangeTracking(s){s.querySelectorAll('input,select,textarea').forEach(el=>{el.addEventListener('input',markAsChanged);el.addEventListener('change',markAsChanged)})}function sleep(ms){return new Promise(r=>setTimeout(r,ms))}async function autofillRow(row){const word=row.querySelector('.word-input')?.value.trim()||'';const context=row.querySelector('.example-input')?.value.trim()||'';const btn=row.querySelector('.autofill-btn');const status=row.querySelector('.status');if(!word){if(status)status.textContent='Enter a word first.';return false}if(btn){btn.disabled=true;btn.textContent='Filling...'}if(status)status.textContent='Filling pronunciation and meaning...';try{const body='word='+encodeURIComponent(word)+'&context='+encodeURIComponent(context);const res=await fetch('/lessons/lessons/api/autofill_word.php',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body,credentials:'same-origin'});const data=await res.json();if(!res.ok||data.error)throw new Error(data.error||'Auto-fill failed');if(data.ipa)row.querySelector('.ipa-input').value=data.ipa;if(data.meaning)row.querySelector('.meaning-input').value=data.meaning;if(status)status.textContent='Auto-fill complete. Review before saving.';markAsChanged();return true}catch(e){if(status)status.textContent='Auto-fill failed. Type manually.';alert('Auto-fill failed. You can type the pronunciation and meaning manually.');return false}finally{if(btn){btn.disabled=false;btn.textContent='Auto-fill pronunciation & meaning'}}}document.addEventListener('DOMContentLoaded',()=>{bindChangeTracking(document);document.getElementById('items').addEventListener('click',e=>{const b=e.target.closest('.autofill-btn');if(b)autofillRow(b.closest('.word-row'))});document.getElementById('autofillAll').addEventListener('click',async()=>{const rows=[...document.querySelectorAll('.word-row')];const all=document.getElementById('autofillAll');all.disabled=true;all.textContent='Filling all...';for(const row of rows){await autofillRow(row);await sleep(300)}all.disabled=false;all.textContent='Auto-fill all words'});document.getElementById('pronunciationForm').addEventListener('submit',()=>{formSubmitted=true;formChanged=false})});window.addEventListener('beforeunload',e=>{if(formChanged&&!formSubmitted){e.preventDefault();e.returnValue=''}});setInterval(()=>fetch(window.location.pathname+window.location.search+'&keepalive=1',{credentials:'same-origin',cache:'no-store'}),120000);
</script>
